props.extensibilityCode:
// Slider controlado com formatador de valor
const [value, setValue] = useState([50]);

<div className="space-y-3">
  <div className="flex items-center justify-between">
    <Label>Volume</Label>
    <span aria-live="polite" className="text-sm tabular-nums">{value[0]}%</span>
  </div>
  <Slider
    value={value}
    onValueChange={setValue}
    min={0}
    max={100}
    step={1}
    aria-label="Volume"
  />
</div>

tokens.customizationCode:
/* Tamanho customizado do Thumb */
[data-slot="slider-thumb"] {
  width: 1rem;
  height: 1rem;
}

/* Cor customizada do Range */
.slider-success [data-slot="slider-range"] {
  @apply bg-green-500;
}

